import React from "react";
import { Link } from "react-router-dom";
import "../index.css";

const Cars = () => {
  const cars = [
    { id: 1, name: "BMW X6", type: "Tự động", seats: 4 },
    { id: 2, name: "Innova", type: "Số sàn", seats: 7 },
  ];

  return (
    <div className="admin-content">
      <div className="d-flex justify-content-between mb-3">
        <h4>Quản lý xe</h4>
        <Link to="/admin/cars/add" className="btn btn-primary">
          <i className="bi bi-plus"></i> Thêm xe
        </Link>
      </div>

      <table className="table table-hover">
        <thead>
          <tr>
            <th>ID</th>
            <th>Tên xe</th>
            <th>Loại</th>
            <th>Số chỗ</th>
            <th>Hành động</th>
          </tr>
        </thead>
        <tbody>
          {cars.map((car) => (
            <tr key={car.id}>
              <td>{car.id}</td>
              <td>{car.name}</td>
              <td>{car.type}</td>
              <td>{car.seats}</td>
              <td>
                <Link
                  to={`/admin/cars/edit/${car.id}`}
                  className="btn btn-sm btn-warning me-2"
                >
                  Sửa
                </Link>
                <button className="btn btn-sm btn-danger">Xóa</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Cars;
